def avg_distance(mapping, interactions, distance_fn):
    total_distance = 0
    total_count = 0

    for (log_q0, log_q1), count in interactions.items():
        phys_q0 = mapping[log_q0]
        phys_q1 = mapping[log_q1]
        dist = distance_fn(phys_q0, phys_q1)
        total_distance += dist * count
        total_count += count

    return total_distance / total_count if total_count else 0

def linear_dist(q0, q1):
    return abs(q0 - q1)

mapping = {0: 0, 1: 2, 2: 4}
interactions = {(0, 1): 3, (1, 2): 1}

print(f"Avg distance: {avg_distance(mapping, interactions, linear_dist)}")
